sql:
SELECT status, AVG(rating) AS average_rating
FROM suggestions
GROUP BY status;

SELECT AVG(rating) AS average_rating, COUNT(*) AS approved_count
FROM suggestions
WHERE status = 'approved';

SELECT DISTINCT u.user_name
FROM suggestions s
INNER JOIN users u ON s.user_id = u.user_id;

SELECT users.user_name, users.email
FROM users
WHERE users.user_id NOT IN (SELECT user_id FROM suggestions);

